const kpi = $('KPI Query').first().json || {};
const topOpps = $('Top Opps Query').all().map(i => i.json);
const seenIds = new Set();
const signals = $('FT Signals Query').all()
  .map(i => i.json)
  .filter(s => { if (seenIds.has(s.signal_id)) return false; seenIds.add(s.signal_id); return true; })
  .slice(0, 5);

let an1 = {};
try { an1 = $('AN1 Query').first().json || {}; } catch(e) {}
const incumbents = an1.incumbents || null;
const an1OppId = an1.opp_id || null;
const an1Agency = an1.agency || null;

const fmt = (v) => {
  const n = Number(v) || 0;
  if (n >= 1e9) return '$' + (n/1e9).toFixed(1) + 'B';
  if (n >= 1e6) return '$' + (n/1e6).toFixed(1) + 'M';
  if (n >= 1e3) return '$' + (n/1e3).toFixed(0) + 'K';
  return n > 0 ? '$' + n : 'TBD';
};

return [{ json: {
  status: 'ok',
  kpis: {
    pursue_count: Number(kpi.pursue_count) || 0,
    evaluate_count: Number(kpi.evaluate_count) || 0,
    monitor_count: Number(kpi.monitor_count) || 0,
    weighted_pipeline: fmt(kpi.weighted_pipeline),
    weighted_pipeline_raw: Number(kpi.weighted_pipeline) || 0,
    ft_signals: Number(kpi.ft_signals) || 0,
    due_30d: Number(kpi.due_30d) || 0,
    pursue_90d_plus: Number(kpi.pursue_90d_plus) || 0,
  },
  top_opportunities: topOpps.map(o => ({
    id: o.id,
    title: o.opp_title || 'Untitled',
    agency: o.agency || '',
    score: o.gda_score,
    label: o.gda_label,
    stage: o.stage,
    value: fmt(o.estimated_value),
    value_raw: Number(o.estimated_value) || 0,
    deadline: o.response_deadline,
    source_url: o.source_url || null,
    naics: o.naics_code,
  })),
  ft_signals: signals.map(s => ({
    id: s.signal_id,
    title: s.title,
    agency: s.agency || '',
    horizon: s.horizon,
    value: fmt(s.estimated_value),
    strength: Number(s.signal_strength) || 0,
    action: s.recommended_action,
    path: s.solution_path,
    source: s.source_id || '',
    source_url: s.source_url || s.external_url || null,
  })),
  incumbent_themes: {
    opp_id: an1OppId,
    agency: an1Agency,
    source: 'gda_incumbent_analysis',
    data_available: !!(incumbents && incumbents.length > 0),
    incumbents: incumbents ? incumbents.slice(0,3) : [],
    message: incumbents && incumbents.length > 0
      ? 'Incumbent vendor data from award history for top PURSUE opp agency.'
      : 'No incumbent award data on file for this agency. Run AN-1 analysis via AI Agent Chat to generate win themes.',
  },
  analysis_status: {
    available: true,
    message: 'Pwin calibration active — 12 weights calibrated from 10 win/loss outcomes. AN-1 incumbent analysis available via AI Agent Chat.',
    pwin_count: 12,
    calibrated: true,
    win_loss_count: 10,
    last_calibrated: '2026-05-04T21:41:44Z',
  },
  daily_actions: {
    available: true,
    message: 'Learning engine calibrated. 10 win/loss outcomes logged. Weights updated 2026-05-04.',
  },
  generated_at: new Date().toISOString(),
}}];
